{
  "plan_id": "RL-001",
  "version": "1.0.0",
  "author": "lane-owner",
  "status": "design",
  "created_at": "2026-05-30",
  "revision": 1,
  "sections": [
    {
      "id": "executive-summary",
      "title": "Executive Summary",
      "body": "The OpenCode desktop app currently has no degraded or safe mode. If any critical subsystem fails during initialization—the sidecar server, database (PGlite/SQLite), DuckDB analytics, MCP servers, or plugins—the app either crashes outright or shows a generic error dialog. Users must resort to Finder/Terminal to fix issues. This document proposes a Safe/Degraded Mode architecture that isolates subsystem failures and keeps the app functional."
    },
    {
      "id": "current-initialization-flow",
      "title": "Current Initialization Flow Map",
      "body": {
        "overview": "The app starts in the Electron main process, spawns a Node.js sidecar utility process that loads the entire opencode server, then opens the renderer window when the sidecar is ready.",
        "sequence": [
          {
            "step": 1,
            "name": "Main process start",
            "file": "packages/desktop/src/main/index.ts",
            "line": 120,
            "detail": "Effect.runFork(main) — main Effect generator"
          },
          {
            "step": 2,
            "name": "Init crash reporter & logging",
            "file": "packages/desktop/src/main/index.ts",
            "line": 128,
            "detail": "initCrashReporter(), initLogging(), startNetLog()"
          },
          {
            "step": 3,
            "name": "Register IPC handlers",
            "file": "packages/desktop/src/main/index.ts",
            "line": 219,
            "detail": "registerIpcHandlers({...}) — all IPC channels"
          },
          {
            "step": 4,
            "name": "Create loading window",
            "file": "packages/desktop/src/main/windows.ts",
            "line": 100,
            "detail": "createLoadingWindow() — overlay with init progress"
          },
          {
            "step": 5,
            "name": "Spawn sidecar process",
            "file": "packages/desktop/src/main/server.ts",
            "line": 120,
            "detail": "spawnLocalServer() — utilityProcess.fork()"
          },
          {
            "step": 6,
            "name": "Sidecar init",
            "file": "packages/desktop/src/main/sidecar.ts",
            "line": 54,
            "detail": "start() — imports virtual:opencode-server"
          },
          {
            "step": 7,
            "name": "Run DB migrations",
            "file": "packages/desktop/src/main/sidecar.ts",
            "line": 63,
            "detail": "JsonMigration.run() — if needsMigration"
          },
          {
            "step": 8,
            "name": "Start HTTP server",
            "file": "packages/desktop/src/main/sidecar.ts",
            "line": 77,
            "detail": "Server.listen() — Effect-based HTTP server"
          },
          {
            "step": 9,
            "name": "Sidecar sends 'ready'",
            "file": "packages/desktop/src/main/sidecar.ts",
            "line": 80,
            "detail": "parentPort.postMessage({ type: 'ready' })"
          },
          {
            "step": 10,
            "name": "Main process opens main window",
            "file": "packages/desktop/src/main/index.ts",
            "line": 340,
            "detail": "createMainWindow() — after serverReady resolved"
          },
          {
            "step": 11,
            "name": "Renderer connects to sidecar",
            "file": "packages/app/src/context/server.tsx",
            "detail": "Connects to sidecar HTTP server via SDK"
          },
          {
            "step": 12,
            "name": "Renderer app boot",
            "file": "packages/app/src/app.tsx",
            "line": 172,
            "detail": "AppBaseProviders, ConnectionGate — renderer boot"
          }
        ]
      }
    },
    {
      "id": "degradation-points",
      "title": "Degradation Points Identified",
      "body": [
        {
          "id": "DP-01",
          "severity": "critical",
          "component": "Sidecar process crash",
          "location": "packages/desktop/src/main/server.ts:151-165",
          "current_behavior": "Sidecar spawner rejects with error if sidecar exits before 'ready'. Main process Effect.catch shows error dialog. App cannot start.",
          "impact": "Complete app failure",
          "existing_protection": "Effect.catch around main generator, but no recovery path beyond showing error dialog"
        },
        {
          "id": "DP-02",
          "severity": "critical",
          "component": "PGlite init failure",
          "location": "packages/opencode/src/storage/db.pg.ts:24-32",
          "current_behavior": "new PGlite(dataDir) with no try/catch. If WASM fails or data dir corrupt, process crashes.",
          "impact": "Sidecar crash → app crash",
          "existing_protection": "None"
        },
        {
          "id": "DP-03",
          "severity": "high",
          "component": "Database migration failure",
          "location": "packages/desktop/src/main/sidecar.ts:63-72",
          "current_behavior": "JsonMigration.run() throws if migration fails. Caught by sidecar's start() catch block → posts error → exits.",
          "impact": "Sidecar crash → app crash",
          "existing_protection": "Sidecar try/catch around entire start()"
        },
        {
          "id": "DP-04",
          "severity": "high",
          "component": "DuckDB init failure",
          "location": "packages/opencode/src/storage/db.duckdb.ts:240-255",
          "current_behavior": "WASM init returns null (deferred), falls back to CLI binary. If CLI binary missing or broken, returns undefined. No crash, but analytics silently disabled.",
          "impact": "Analytics/timeline disabled silently",
          "existing_protection": "WASM→CLI fallback, but no user notification"
        },
        {
          "id": "DP-05",
          "severity": "high",
          "component": "MCP server init failure",
          "location": "packages/opencode/src/mcp/index.ts:560-620",
          "current_behavior": "MCP servers connect during session init. StdioClientTransport spawns child processes. If a server binary is missing or crashes, MCP.Service collects errors but doesn't propagate to crash the app.",
          "impact": "Individual MCP server fails, user sees no error",
          "existing_protection": "Per-server error isolation via Semaphore and serverLocks map"
        },
        {
          "id": "DP-06",
          "severity": "medium",
          "component": "Plugin crash",
          "location": "packages/opencode/src/plugin/",
          "current_behavior": "Plugin errors are caught per-invocation. No quarantine mechanism. A crashing plugin can repeatedly fail.",
          "impact": "Repeated errors, no isolation",
          "existing_protection": "Try/catch per tool invocation, but no auto-disable"
        },
        {
          "id": "DP-07",
          "severity": "high",
          "component": "Agent loop crash",
          "location": "packages/opencode/src/session/",
          "current_behavior": "Agent loop runs in Effect fibers. If LLM backend fails, session errors. No session persistence for resume/recovery.",
          "impact": "Lost session state",
          "existing_protection": "None for session persistence"
        },
        {
          "id": "DP-08",
          "severity": "medium",
          "component": "Sidecar timeout during init",
          "location": "packages/desktop/src/main/server.ts:165",
          "current_behavior": "Hardcoded TIMEOUT. If sidecar doesn't become ready in time, spawner rejects with timeout error.",
          "impact": "App shows error dialog",
          "existing_protection": "Timeout with error message"
        },
        {
          "id": "DP-09",
          "severity": "low",
          "component": "Config load failure",
          "location": "packages/opencode/src/config/",
          "current_behavior": "Config loads from filesystem. Corrupt config files can cause errors during server init.",
          "impact": "Server fails to start",
          "existing_protection": "None beyond Effect error handling"
        }
      ]
    },
    {
      "id": "proposed-architecture",
      "title": "Proposed Safe/Degraded Mode Architecture",
      "body": {
        "overview": "Three-tier architecture: Tier 1 = Safe Mode (app loads with minimal UI), Tier 2 = Degraded Mode (core app works, features disabled), Tier 3 = Full Mode (everything operational).",
        "tiers": [
          {
            "tier": 1,
            "name": "Safe Mode",
            "entry_conditions": [
              "Sidecar process crashes or fails to start",
              "Database initialization fails (PGlite/SQLite corrupt)",
              "Database migration fails irrecoverably",
              "Explicit user request via CLI flag (--safe-mode)",
              "Detected from previous session crash marker"
            ],
            "behavior": "Loading window detects sidecar failure → transitions to Safe Mode UI instead of showing error dialog. User sees diagnostic/inspection panel. No database access. Read-only project tree. Repair actions available.",
            "ui_components": {
              "view_sessions": "Read session data from JSONL backups if available",
              "export_debug_packet": "Bundle logs, config, system info into downloadable archive",
              "open_logs": "Open log directory in file manager",
              "repair_database": "Attempt DB repair: truncate corrupt tables, rebuild from backup, or reset",
              "disable_plugins": "Toggle all plugins off for safe restart",
              "disable_mcp_servers": "Toggle all MCP servers off for safe restart",
              "clear_stale_locks": "Remove filesystem lock files from crashed sessions",
              "rollback_migration": "Restore previous migration backup",
              "open_project_readonly": "Mount project tree without file watcher or indexing",
              "reset_app_config": "Reset config to factory defaults (with backup preservation)",
              "copy_diagnostic_summary": "Copy structured diagnostic JSON to clipboard"
            }
          },
          {
            "tier": 2,
            "name": "Degraded Mode",
            "entry_conditions": [
              "Sidecar starts but DuckDB init fails → analytics disabled",
              "Sidecar starts but MCP server(s) fail → MCP panel disabled",
              "Sidecar starts but plugin crash → plugin quarantined",
              "Sidecar starts but agent loop init fails → session execution disabled"
            ],
            "behavior": "App loads in full mode. Feature panels show 'disabled' state with explanation. Repair actions available per component. User can continue working with core functionality.",
            "degradations": [
              {
                "component": "DuckDB/Analytics",
                "impact": "Timeline works, analytics tab shows 'Analytics unavailable' with reason. DuckDB panels disabled.",
                "recovery": "Re-init DuckDB button, check binary path"
              },
              {
                "component": "MCP Servers",
                "impact": "MCP panel shows failed servers with error message. User can disable/edit/retry servers individually.",
                "recovery": "Retry connection, edit configuration, disable server"
              },
              {
                "component": "Plugins",
                "impact": "Crashing plugin auto-quarantined with dialog: 'Plugin X crashed N times. Disable?'. Plugin toggle shows error state.",
                "recovery": "Disable, reconfigure, or update plugin"
              },
              {
                "component": "Agent Loop",
                "impact": "Session creation blocked. 'Agent unavailable' status shown. Existing sessions preserved.",
                "recovery": "Retry agent init, check LLM provider config"
              },
              {
                "component": "Database Migration",
                "impact": "App opens with 'Migration Required' banner. Read-only mode for database features.",
                "recovery": "Rollback migration, retry migration, repair database"
              }
            ]
          },
          {
            "tier": 3,
            "name": "Full Mode",
            "behavior": "All subsystems operational. Current application behavior."
          }
        ]
      }
    },
    {
      "id": "implementation-plan",
      "title": "Implementation Plan & Key File Changes",
      "body": {
        "phase_1": {
          "name": "Init Flow Restructuring",
          "description": "Restructure the main process init to detect sidecar failure and transition to Safe Mode instead of crashing.",
          "files": [
            {
              "path": "packages/desktop/src/main/index.ts",
              "changes": [
                "Add Safe Mode detection after sidecar timeout/failure",
                "Add --safe-mode CLI flag handling",
                "Create safe mode window path (separate HTML entry point or route)",
                "Add crash detection from previous session (check lock file / exit code)",
                "Extend InitStep type with safe_mode and degraded_mode phases"
              ]
            },
            {
              "path": "packages/desktop/src/main/server.ts",
              "changes": [
                "Return distinct error types for sidecar failure (timeout, crash, migration_fail)",
                "Expose spawn error details for safe mode routing"
              ]
            },
            {
              "path": "packages/desktop/src/main/sidecar.ts",
              "changes": [
                "Add granular error reporting: distinguish DB failure vs migration failure vs server failure",
                "Add startup health report with per-component status",
                "Graceful degradation: if DuckDB fails, server starts with analytics disabled",
                "If PGlite init fails before server starts → tell main process → trigger Safe Mode"
              ]
            },
            {
              "path": "packages/desktop/src/preload/types.ts",
              "changes": [
                "Extend InitStep: phase: 'safe_mode' | 'degraded_mode'",
                "Add SystemHealth type with per-component status",
                "Add SafeModeActions type for IPC API"
              ]
            },
            {
              "path": "packages/desktop/src/preload/index.ts",
              "changes": [
                "Add safe mode IPC bridge methods (exportDebugLogs, repairDb, etc.)"
              ]
            },
            {
              "path": "packages/desktop/src/main/ipc-init.ts",
              "changes": [
                "Register IPC handlers for safe mode actions",
                "Add health report IPC channel"
              ]
            },
            {
              "path": "packages/desktop/src/main/windows.ts",
              "changes": [
                "Add createSafeModeWindow() function",
                "Modify loading window to transition to safe mode window on failure"
              ]
            }
          ]
        },
        "phase_2": {
          "name": "Service Health Registry",
          "description": "Build a service registry with health tracking and feature gating.",
          "files": [
            {
              "path": "packages/opencode/src/server/health.ts",
              "changes": [
                "NEW FILE: ServiceHealth type (enum: healthy | degraded | down)",
                "HealthRegistry: Effect service that tracks all subsystem statuses",
                "Status change events for pushing to UI"
              ]
            },
            {
              "path": "packages/opencode/src/server/server.ts",
              "changes": [
                "Wire HealthRegistry into server initialization",
                "Expose /global/health endpoint with per-service breakdown"
              ]
            },
            {
              "path": "packages/opencode/src/storage/db.pg.ts",
              "changes": [
                "Wrap new PGlite() in try/catch",
                "Report status to HealthRegistry on init success/failure"
              ]
            },
            {
              "path": "packages/opencode/src/storage/db.duckdb.ts",
              "changes": [
                "Report DuckDB init status to HealthRegistry",
                "No-op gracefully when DuckDB unavailable"
              ]
            },
            {
              "path": "packages/opencode/src/storage/adapter.ts",
              "changes": [
                "Wire DatabaseAdapter init to HealthRegistry"
              ]
            },
            {
              "path": "packages/opencode/src/mcp/index.ts",
              "changes": [
                "Report per-MCP-server status to HealthRegistry",
                "Server-level error isolation with auto-disable after N crashes"
              ]
            },
            {
              "path": "packages/opencode/src/plugin/index.ts",
              "changes": [
                "Add crash counter per plugin",
                "Auto-quarantine plugin after N crashes (e.g., 3 consecutive)",
                "Report plugin statuses to HealthRegistry"
              ]
            }
          ]
        },
        "phase_3": {
          "name": "Safe Mode UI",
          "description": "Build the Safe Mode user interface.",
          "files": [
            {
              "path": "packages/app/src/app.tsx",
              "changes": [
                "Add safe mode route detection",
                "If InitStep is safe_mode, render SafeModePage instead of main app"
              ]
            },
            {
              "path": "packages/app/src/pages/safe-mode.tsx",
              "changes": [
                "NEW FILE: Safe mode landing page with diagnostic summary"
              ]
            },
            {
              "path": "packages/app/src/components/safe-mode/*.tsx",
              "changes": [
                "NEW FILES: Safe mode action card components",
                "export-debug-packet.tsx, view-logs.tsx, repair-database.tsx",
                "disable-plugins.tsx, disable-mcp.tsx, clear-locks.tsx",
                "rollback-migration.tsx, open-project-readonly.tsx",
                "reset-config.tsx, copy-diagnostics.tsx, view-sessions.tsx"
              ]
            },
            {
              "path": "packages/app/src/i18n/en.ts",
              "changes": [
                "Add safe mode translation strings (~30 keys)"
              ]
            },
            {
              "path": "packages/desktop/src/main/desktop-menu-actions.ts",
              "changes": [
                "Disable menu items that require full mode",
                "Add safe mode indicator in menu"
              ]
            }
          ]
        },
        "phase_4": {
          "name": "Degraded Mode UI",
          "description": "Feature-level degradation indicators and controls.",
          "files": [
            {
              "path": "packages/app/src/context/server.tsx",
              "changes": [
                "Expose health status from /global/health endpoint",
                "Provide per-component health context"
              ]
            },
            {
              "path": "packages/app/src/context/server-health.tsx",
              "changes": [
                "NEW FILE: Solid.js reactive health store",
                "Polls /global/health, maintains status map",
                "Provides useHealth() hook for components"
              ]
            },
            {
              "path": "packages/app/src/components/status-bar.tsx",
              "changes": [
                "Add health indicator icon in status bar",
                "Show degraded subsystem count"
              ]
            },
            {
              "path": "packages/app/src/components/mcp/mcp-panel.tsx",
              "changes": [
                "Show 'MCP Unavailable' when MCP service is down",
                "Per-server error states with retry/disable actions"
              ]
            },
            {
              "path": "packages/app/src/components/analytics/*.tsx",
              "changes": [
                "Show 'Analytics Unavailable' when DuckDB is down",
                "Disable analytics-only features"
              ]
            },
            {
              "path": "packages/app/src/components/plugin/*.tsx",
              "changes": [
                "Show quarantine state for disabled plugins",
                "Plugin crash notification with disable option"
              ]
            },
            {
              "path": "packages/app/src/components/session/*.tsx",
              "changes": [
                "Show 'Agent Unavailable' when agent loop is down",
                "Offer resume/recover for lost sessions"
              ]
            }
          ]
        },
        "phase_5": {
          "name": "Session Preservation & Recovery",
          "description": "Preserve session state for recovery after crashes.",
          "files": [
            {
              "path": "packages/opencode/src/session/persistence.ts",
              "changes": [
                "NEW FILE: Periodic session state snapshots to JSONL",
                "Crash detection from stale lock files",
                "Session resume endpoint"
              ]
            },
            {
              "path": "packages/opencode/src/session/processor.ts",
              "changes": [
                "Add crash-safe state transitions",
                "Wrap agent loop in recovery fiber"
              ]
            }
          ]
        },
        "phase_6": {
          "name": "Migration Backup & Rollback",
          "description": "Backup before migrations, offer rollback on failure.",
          "files": [
            {
              "path": "packages/desktop/src/main/sidecar.ts",
              "changes": [
                "Backup database before migration",
                "On migration failure → offer rollback, don't crash immediately"
              ]
            },
            {
              "path": "packages/opencode/src/storage/migrate.ts",
              "changes": [
                "Add backup/restore utilities",
                "Report migration status to init step emitter"
              ]
            }
          ]
        }
      }
    },
    {
      "id": "key-decision-records",
      "title": "Key Architecture Decisions",
      "body": [
        {
          "kdr": "ADR-001",
          "decision": "Safe Mode runs in the same Electron renderer process, not a separate window",
          "rationale": "Simplifies IPC bridge reuse. Safe mode UI can share preload bridge and existing IPC handlers. A separate process would require duplicating the entire Electron preload/sandbox setup."
        },
        {
          "kdr": "ADR-002",
          "decision": "Health registry is an Effect Service in the opencode server, reported via /global/health",
          "rationale": "Existing health check infrastructure already uses /global/health endpoint. Extending it with per-service breakdown avoids new communication channels. The renderer polls this endpoint via existing useServerHealth hook."
        },
        {
          "kdr": "ADR-003",
          "decision": "Safe mode diagnosis uses static HTML/JS bundled with the app (no server needed)",
          "rationale": "Safe Mode must work when the server is down. The safe mode UI loads as a separate route in the renderer bundle, powered only by the Electron preload bridge (filesystem access, IPC to main process)."
        },
        {
          "kdr": "ADR-004",
          "decision": "InitStep discriminated union is extended with detailed error phases",
          "rationale": "Existing pattern of { phase: 'server_waiting' | 'sqlite_waiting' | 'done' } already works well. Extending with 'safe_mode', 'degraded_mode', and error detail fields allows the loading window to transition correctly."
        },
        {
          "kdr": "ADR-005",
          "decision": "Plugin quarantine uses crash counters stored in config, not in-memory",
          "rationale": "Persistent quarantine survives app restart. A plugin that crashed 3 times stays disabled across sessions until user explicitly re-enables it. In-memory counters would reset on restart."
        },
        {
          "kdr": "ADR-006",
          "decision": "Sidecar communicates component status via typed IPC messages, not just exit codes",
          "rationale": "The sidecar's error message currently is { type: 'error', error: { message, stack } }. We extend this with { type: 'status', components: { db: 'ok'|'degraded'|'fail', mcp: {...} } } so the main process can decide whether to offer Safe Mode or Degraded Mode."
        }
      ]
    },
    {
      "id": "risk-assessment",
      "title": "Risk Assessment",
      "body": [
        {
          "risk": "Init flow complexity increases",
          "severity": "medium",
          "mitigation": "The three-tier model (Safe → Degraded → Full) adds conditional paths. Keep the init flow as a simple state machine. Each tier is a distinct code path, not nested conditionals.",
          "detection": "Code review of main/index.ts state transitions"
        },
        {
          "risk": "Safe mode UI must work without server",
          "severity": "high",
          "mitigation": "Safe mode uses only Electron preload bridge APIs (filesystem, IPC to main process). No HTTP calls. The main process handles all safe mode actions directly.",
          "detection": "Test safe mode actions in isolation (disable server)"
        },
        {
          "risk": "Sidecar health reporting adds IPC message complexity",
          "severity": "low",
          "mitigation": "Extend existing SidecarMessage union type with 'status' variant. Main process already handles sidecar messages for 'ready', 'error', 'sqlite'.",
          "detection": "TypeScript type checking ensures all message variants handled"
        },
        {
          "risk": "Plugin quarantine could disable legitimately failing plugins",
          "severity": "low",
          "mitigation": "Crash threshold is configurable (default 3). User can always re-enable from plugin settings. Diagnostic info shown per quarantine.",
          "detection": "User feedback on false positives"
        },
        {
          "risk": "Migration backup could double disk usage for large databases",
          "severity": "medium",
          "mitigation": "Use hard links on supported filesystems, or incremental backup. Single backup retained. User warned before migration on large datasets (>100MB).",
          "detection": "Size check before migration"
        },
        {
          "risk": "Preload bridge surface area increases with safe mode actions",
          "severity": "low",
          "mitigation": "Safe mode IPC handlers are self-contained and access only filesystem and Electron APIs. Existing security model (contextBridge, typedInvoke) applies.",
          "detection": "Security audit of safe mode IPC handlers"
        },
        {
          "risk": "Dependency: Effect.ts version compatibility",
          "severity": "low",
          "mitigation": "The codebase already uses Effect.ts throughout. HealthRegistry follows existing pattern (Context.Service + Layer).",
          "detection": "TypeScript compilation"
        }
      ]
    },
    {
      "id": "claims-calibration",
      "title": "Claims Calibration",
      "body": {
        "verified_claims": [
          "The app has NO existing degraded mode (all initializations crash on failure)",
          "Sidecar is a single point of failure (if it fails, app cannot start)",
          "PGlite init has zero error handling (no try/catch around constructor)",
          "DuckDB silently degrades (WASM→CLI fallback, but no user notification)",
          "MCP servers already have per-instance isolation via Semaphore and serverLocks",
          "Plugins have error handling but no quarantine/persistent disable",
          "InitStep type exists but has only 3 phases (server_waiting, sqlite_waiting, done)",
          "Loading window and wireWindowRecovery already exist as crash UI patterns",
          "The app uses Effect.ts extensively (Context, Layer, Service pattern)",
          "Preload bridge uses typedInvoke/safeInvoke with structured error handling"
        ],
        "unverified_claims": [
          "Specific error messages from the sidecar during init failures",
          "Exact timing of loading window transitions",
          "Current session persistence format for crash recovery",
          "Size of database files for migration backup estimation"
        ]
      }
    },
    {
      "id": "files-summary",
      "title": "Files Summary",
      "body": {
        "new_files": [
          "packages/opencode/src/server/health.ts — Health Registry service",
          "packages/app/src/pages/safe-mode.tsx — Safe mode landing page",
          "packages/app/src/components/safe-mode/*.tsx — Safe mode action cards (10+ components)",
          "packages/app/src/context/server-health.tsx — Reactive health store",
          "packages/opencode/src/session/persistence.ts — Session state persistence",
          "packages/opencode/src/storage/backup.ts — Database backup/restore utilities"
        ],
        "modified_files": [
          "packages/desktop/src/main/index.ts — Init flow restructuring, safe mode routing",
          "packages/desktop/src/main/server.ts — Sidecar error type differentiation",
          "packages/desktop/src/main/sidecar.ts — Component status IPC messages",
          "packages/desktop/src/main/windows.ts — Safe mode window creation",
          "packages/desktop/src/preload/types.ts — Extended InitStep, SystemHealth, SafeModeActions",
          "packages/desktop/src/preload/index.ts — Safe mode IPC bridge methods",
          "packages/desktop/src/main/ipc-init.ts — Safe mode IPC handlers",
          "packages/opencode/src/server/server.ts — Wire HealthRegistry",
          "packages/opencode/src/storage/db.pg.ts — Error handling around PGlite init",
          "packages/opencode/src/storage/db.duckdb.ts — Health reporting",
